-- FK: domain_recon.engagementId → engagements.id
DELETE FROM domain_recon WHERE engagementId NOT IN (SELECT id FROM engagements);
ALTER TABLE domain_recon 
ADD CONSTRAINT fk_dr_engagement 
FOREIGN KEY (engagementId) REFERENCES engagements(id) ON DELETE CASCADE;

-- FK: osint_findings.engagementId → engagements.id (nullable)
DELETE FROM osint_findings WHERE engagementId IS NOT NULL AND engagementId NOT IN (SELECT id FROM engagements);
ALTER TABLE osint_findings 
ADD CONSTRAINT fk_of_engagement 
FOREIGN KEY (engagementId) REFERENCES engagements(id) ON DELETE SET NULL;

-- FK: typosquat_domains.engagementId → engagements.id
DELETE FROM typosquat_domains WHERE engagementId NOT IN (SELECT id FROM engagements);
ALTER TABLE typosquat_domains 
ADD CONSTRAINT fk_td_engagement 
FOREIGN KEY (engagementId) REFERENCES engagements(id) ON DELETE CASCADE;

-- FK: domain_intel_scans.engagementId → engagements.id (nullable)
UPDATE domain_intel_scans SET engagementId = NULL WHERE engagementId IS NOT NULL AND engagementId NOT IN (SELECT id FROM engagements);
ALTER TABLE domain_intel_scans 
ADD CONSTRAINT fk_dis_engagement 
FOREIGN KEY (engagementId) REFERENCES engagements(id) ON DELETE SET NULL;

